let _mailService: MailService | null = null;

export function getMailService(): MailService {
  if (!_mailService) {
    _mailService = new MailService();
  }
  return _mailService;
}

export function resetMailService(): void {
  if (_mailService) {
    void _mailService.shutdown();
    _mailService = null;
  }
